                  type="text"
                  placeholder="e.g., +1-555-999-0000"
                  value={formData.emergencyContact}
                  onChange={(e) => handleInputChange('emergencyContact', e.target.value)}
                  style={styles.input}
                />
              </div>
              
              <div style={styles.formField}>
                <label style={styles.label}>Profile Picture</label>
                <input
                  type="file"
                  ref={fileInputRef}
                  onChange={handleFileSelect}
                  accept="image/*"
                  style={{ display: 'none' }}
                />
                
                {/* Preview */}
                <div style={styles.previewContainer}>
                  {(() => {
                    const displayUrl = previewUrl || (formData.profilePictureUrl 
                      ? (formData.profilePictureUrl.startsWith('http') ? formData.profilePictureUrl : `http://localhost:8080${formData.profilePictureUrl}`)
                      : null);
                    return displayUrl ? (
                      <img 
                        src={displayUrl} 
                        alt="Profile Preview"
                        style={styles.previewImage}
                        onError={(e) => {
                          e.target.style.display = 'none';
                        }}
                      />
                    ) : (
                      <div style={styles.previewPlaceholder}>
                        <span style={styles.previewPlaceholderText}>
                          {formData.fullName ? formData.fullName.charAt(0).toUpperCase() : '?'}
                        </span>
                      </div>
                    );
                  })()}
                </div>
                
                {/* Upload Button */}
                <button
                  type="button"
                  onClick={triggerFileInput}
                  disabled={uploading}
                  style={styles.uploadBtn}
                >
                  {uploading ? 'Uploading...' : '📁 Choose File'}
                </button>
                
                {/* URL Display (read-only) */}
                {formData.profilePictureUrl && (
                  <input
                    type="text"
                    value={formData.profilePictureUrl}
                    readOnly
                    style={{...styles.input, marginTop: '10px', fontSize: '12px', backgroundColor: '#f5f5f5'}}
                  />
                )}
              </div>
            </div>
          </div>

          <button type="submit" style={styles.submitBtn}>
            {editingId ? 'Update Employee' : 'Create Employee'}
          </button>
        </form>
      )}

      <div style={styles.tableContainer}>
        <table style={styles.table}>
          <thead>
            <tr>
              <th style={styles.th}>ID</th>
              <th style={styles.th}>Photo</th>
              <th style={styles.th}>Name</th>
              <th style={styles.th}>Username</th>
              <th style={styles.th}>Role</th>
              <th style={styles.th}>Department</th>
              <th style={styles.th}>Phone</th>
              <th style={styles.th}>Actions</th>
            </tr>
          </thead>
          <tbody>
            {employees.map((emp) => {
              const fullImageUrl = emp.profilePictureUrl 
                ? (emp.profilePictureUrl.startsWith('http') ? emp.profilePictureUrl : `http://localhost:8080${emp.profilePictureUrl}`)
                : null;
              return (
              <tr key={emp.id} style={styles.tr}>
                <td style={styles.td}>{emp.id}</td>
                <td style={styles.td}>
                  {fullImageUrl ? (
                    <img 
                      src={fullImageUrl} 
                      alt={emp.fullName}
                      style={styles.profilePic}
                      onError={(e) => {
                        e.target.style.display = 'none';
                        e.target.nextSibling.style.display = 'flex';
                      }}
                    />
                  ) : null}
                  <div style={{
                    ...styles.profilePicPlaceholder,
                    display: fullImageUrl ? 'none' : 'flex'
                  }}>
                    {emp.fullName?.charAt(0).toUpperCase()}
                  </div>
                </td>
                <td style={styles.td}>{emp.fullName}</td>
                <td style={styles.td}>{emp.username}</td>
                <td style={styles.td}>
                  <span style={styles.roleBadge}>{emp.role?.replace('_', ' ')}</span>
                </td>
                <td style={styles.td}>{emp.department || '-'}</td>
                <td style={styles.td}>{emp.phoneNumber || '-'}</td>
                <td style={styles.td}>
                  <button style={styles.editBtn} onClick={() => handleEdit(emp)}>Edit</button>
                  <button style={styles.deleteBtn} onClick={() => handleDelete(emp.id)}>Delete</button>
                </td>
              </tr>
              );
            })}
          </tbody>
        </table>
      </div>
    </div>
  );
};

